const out = [];
for (const sku of order) {
  const distinctBins = skuBins.get(sku).size;   // k
  const rep = 1 + 10 * (distinctBins - 1);      // 1, 11, 21, ...
  for (let i = 0; i < rep; i++) out.push(sku);
}

// 3) Kết quả
return [{
  json: {
    joined: out.join(','),
    count: order.length,       // số SKU distinct trước khi join
    expanded_count: out.length // nếu cần kiểm soát
  }
}];

